export function getPresetBySlug(slug: string): PresetAgent | undefined {
  return PRESET_AGENTS.find(a => a.id === slug);
}

export function getPresetsByCategory(category: string): PresetAgent[] {
  return PRESET_AGENTS.filter(a => a.category === category);
}

export function searchPresets(query: string): PresetAgent[] {
  const q = query.toLowerCase();
  return PRESET_AGENTS.filter(
    a => a.name.toLowerCase().includes(q) || a.description.toLowerCase().includes(q)
  );
}